module RefModule(
   // Inputs
   clk,
   rst,
   // Outputs
   count
   );input clk;
   input rst;
   output reg [4-1:1-1] count;

   always @(posedge clk) begin
      if (rst) begin
         count <= 4'b0000;
      end
      else begin
         count <= count + 1;
      end
   end

endmodule
